module top_module(out, clk, rst);output reg [3:0] out;
  input clk, rst;

  wire feedback;

  wire inverted_feedback = ~(out[3] ^ out[2]);
  assign feedback = inverted_feedback;

always @(posedge clk, posedge rst)
  begin
    if (rst)
      out = 4'b0;
    else
      out = {out[2:0],feedback};
  end
endmodule
